# ── File existence ────────────────────────────────────────────────────────────

@pytest.mark.parametrize("rel_path", V241_FILES)
def test_v241_file_exists(rel_path):
    assert (ROOT / rel_path).exists(), f"v2.4.1 file missing: {rel_path}"


def test_v241_script_executable():
    path = ROOT / V241_SCRIPT
    assert path.exists()
    assert os.access(path, os.X_OK), f"Script not executable: {V241_SCRIPT}"


# ── Attribution audit ─────────────────────────────────────────────────────────

@pytest.mark.parametrize("rel_path", V241_FILES)
def test_no_external_attribution(rel_path):
    path = ROOT / rel_path
    if not path.exists():
        pytest.skip(f"File not found: {rel_path}")
    content = path.read_text()
    for phrase in ATTRIBUTION_STRINGS:
        assert phrase not in content, (
            f"External attribution found in {rel_path}: {phrase!r}"
        )


# ── Doc required terms ────────────────────────────────────────────────────────

@pytest.mark.parametrize("term", DOC_REQUIRED_TERMS)
def test_doc_contains_required_term(term):
    doc = ROOT / V241_DOC
    assert doc.exists()
    assert term in doc.read_text(), (
        f"v2.4.1 doc missing required term: {term!r}"
    )


# ── Claim boundary assertions ─────────────────────────────────────────────────

def test_doc_says_not_photo_realistic():
    doc = ROOT / V241_DOC
    content = doc.read_text().lower()
    assert "not photo-realistic" in content, (
        "Doc must explicitly state the stage is NOT photo-realistic"
    )


def test_doc_says_no_valid_rosbag_recorded():
    doc = ROOT / V241_DOC
    content = doc.read_text()
    assert "Pending" in content
    assert "rosbag" in content.lower() or "rosbag2" in content.lower()
    assert "message_count" in content, (
        "Doc must reference message_count check to show no valid bag yet"
    )


def test_doc_says_ros2_publisher_pending():
    doc = ROOT / V241_DOC
    content = doc.read_text()
    assert "Pending" in content
    assert "OmniGraph" in content, (
        "Doc must say OmniGraph publisher nodes are still pending"
    )


def test_doc_explains_why_previous_usd_was_empty():
    doc = ROOT / V241_DOC
    content = doc.read_text()
    assert "absolute" in content.lower() or "reference" in content.lower(), (
        "Doc must explain that the previous USD was an absolute-path reference"
    )


def test_doc_lists_all_five_scaffold_node_types():
    doc = ROOT / V241_DOC
    content = doc.read_text()
    assert "ROS2PublishImage" in content
    assert "ROS2PublishOdometry" in content
    assert "ROS2PublishTransformTree" in content
    assert "ROS2PublishLaserScan" in content
    assert "ROS2SubscribeTwist" in content


