# ── Dry-run execution ─────────────────────────────────────────────────────────

def test_script_dry_run_exits_zero():
    result = subprocess.run(
        [sys.executable, str(ROOT / V241_SCRIPT), "--dry-run"],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert result.returncode == 0, (
        f"create_yahboom_visible_placeholder_stage.py --dry-run failed:\n"
        f"stdout: {result.stdout}\nstderr: {result.stderr}"
    )
    assert "[DRY-RUN]" in result.stdout
    assert "[OK]" in result.stdout


def test_script_dry_run_prints_usda_content():
    result = subprocess.run(
        [sys.executable, str(ROOT / V241_SCRIPT), "--dry-run"],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    out = result.stdout
    assert "#usda 1.0" in out
    assert "base_link" in out
    assert "camera_link" in out
    assert "lidar_link" in out
    assert "wheel_1" in out
    assert "Ground" in out


def test_script_exits_zero():
    result = subprocess.run(
        [sys.executable, str(ROOT / V241_SCRIPT)],
        capture_output=True,
        text=True,
        cwd=str(ROOT),
    )
    assert result.returncode == 0, (
        f"create_yahboom_visible_placeholder_stage.py failed:\n"
        f"stdout: {result.stdout}\nstderr: {result.stderr}"
    )
    assert "[OK]" in result.stdout


# ── USDA file content ─────────────────────────────────────────────────────────

def test_usda_file_exists_or_is_generated():
    usda = ROOT / USDA_PATH
    if not usda.exists():
        # Generate it
        result = subprocess.run(
            [sys.executable, str(ROOT / V241_SCRIPT)],
            capture_output=True,
            text=True,
            cwd=str(ROOT),
        )
        assert result.returncode == 0, "Generator must exit 0"
    assert usda.exists(), f"USDA file must exist: {USDA_PATH}"


@pytest.mark.parametrize("prim", REQUIRED_PRIMS)
def test_usda_contains_prim(prim):
    usda = ROOT / USDA_PATH
    if not usda.exists():
        pytest.skip("USDA not yet generated; run create_yahboom_visible_placeholder_stage.py")
    assert f'"{prim}"' in usda.read_text(), (
        f"USDA must contain prim definition: {prim!r}"
    )


def test_usda_has_correct_up_axis():
    usda = ROOT / USDA_PATH
    if not usda.exists():
        pytest.skip("USDA not yet generated")
    assert 'upAxis = "Z"' in usda.read_text(), (
        "USDA must declare upAxis = Z (standard for robotics)"
    )


def test_usda_has_metres_per_unit():
    usda = ROOT / USDA_PATH
    if not usda.exists():
        pytest.skip("USDA not yet generated")
    assert "metersPerUnit = 1" in usda.read_text(), (
        "USDA must use metersPerUnit = 1 (SI units)"
    )


def test_usda_has_scaffold_comments():
    usda = ROOT / USDA_PATH
    if not usda.exists():
        pytest.skip("USDA not yet generated")
    content = usda.read_text()
    assert "ROS2Publish" in content, (
        "USDA scaffold comments must mention ROS2 publisher nodes"
    )
    assert "/camera/image_raw" in content
    assert "/odom" in content
    assert "Pending" in content


@pytest.mark.parametrize("topic", NOVA_CARTER_TOPICS)
def test_usda_does_not_reference_nova_carter(topic):
    usda = ROOT / USDA_PATH
    if not usda.exists():
        pytest.skip("USDA not yet generated")
    assert topic not in usda.read_text(), (
        f"USDA must not reference Nova Carter topic: {topic}"
    )


def test_usda_has_no_absolute_paths():
    usda = ROOT / USDA_PATH
    if not usda.exists():
        pytest.skip("USDA not yet generated")
    content = usda.read_text()
    assert "/home/" not in content, (
        "USDA must not contain absolute filesystem paths — previous reference bug"
    )
    assert "FleetSafe-VisualNav-Benchmark" not in content, (
        "USDA must not reference the external FleetSafe benchmark repo path"
    )


